checker_dsl:
EXISTS (`method call MC`) {
  AND {
    (`the qualifier type of MC is an array type`),
    EXISTS (`method M`) {
      AND {
        (`M is the method called at MC`),
        OR {
          (`M is the hashCode method from Object class`),
          AND {
            (`M is the equals method from Object class`),
            (`the type of the first argument of MC, when viewed as an array type, has a non-empty intersection with the qualifier array type of MC`)
          }
        }
      }
    }
  }
}
